{
  "name": "ablang2",
  "category": "embedding",
  "image_tag": "ablang2:1.0.0",
  "requires_gpu": true,
  "gpu_count": 1,
  "default_timeout": 600,
  "supports_batch": true,
  "version": "1.0.0",
  "description": "Extract antibody sequence embeddings using AbLang2 (45M parameters, 12 layers, 480-dim). Supports paired and unpaired sequences.",
  "input_schema": {
    "$defs": {
      "AntibodySequence": {
        "description": "A single antibody sequence entry with optional heavy and light chains.\n\nAt least one of ``heavy_chain`` or ``light_chain`` must be provided.",
        "properties": {
          "id": {
            "description": "Unique identifier for this antibody sequence.",
            "title": "Id",
            "type": "string"
          },
          "heavy_chain": {
            "anyOf": [
              {
                "type": "string"
              },
              {
                "type": "null"
              }
            ],
            "default": null,
            "description": "Variable heavy (VH) amino acid sequence.",
            "title": "Heavy Chain"
          },
          "light_chain": {
            "anyOf": [
              {
                "type": "string"
              },
              {
                "type": "null"
              }
            ],
            "default": null,
            "description": "Variable light (VL) amino acid sequence.",
            "title": "Light Chain"
          }
        },
        "required": [
          "id"
        ],
        "title": "AntibodySequence",
        "type": "object"
      }
    },
    "description": "Input schema for antibody language model tools.\n\nUsed by all antibody LM tools (CurrAb, BALM-paired, BALM-unpaired,\nft-ESM, AbLang2, AntiBERTa2) for both embedding extraction and pseudo\nlog-likelihood.",
    "properties": {
      "extra": {
        "additionalProperties": true,
        "description": "Tool-specific parameters passed through to the container. Keys and values are forwarded as-is into config.json.",
        "title": "Extra",
        "type": "object"
      },
      "sequences": {
        "description": "One or more antibody sequences to process.",
        "items": {
          "$ref": "#/$defs/AntibodySequence"
        },
        "title": "Sequences",
        "type": "array"
      },
      "layer": {
        "anyOf": [
          {
            "type": "integer"
          },
          {
            "type": "null"
          }
        ],
        "default": null,
